    name: "empty config (all defaults)",
    input: {},
    expected: {
      version: 1,
      tts: { voiceId: "Sierra" },
      summarizer: { enabled: true }
    }
  }
];

let passed = 0;
let failed = 0;

for (const test of tests) {
  process.stdout.write(`\n📋 ${test.name}... `);

  // Write test config
  writeFileSync(TEST_CONFIG_PATH, JSON.stringify(test.input));

  try {
    // Test the migration logic by importing the module
    // Since we can't easily mock the CONFIG_PATH, we'll verify the schema directly
    const { z } = await import("zod");

    // Define the schema (same as in config.ts)
    const TTSConfigSchema = z.object({
      voiceId: z.string().default("Sierra"),
      bitrate: z.string().default("192k"),
      speed: z.number().min(-1).max(1).default(0),
      pitch: z.number().min(0.5).max(1.5).default(1.0),
      maxChunkChars: z.number().int().min(1).max(1000).default(900)
    });

    const BehaviorConfigSchema = z.object({
      shortcut: z.string().default("alt+r"),
