        } else if (test.expectedErrorContains) {
          console.log("❌ FAIL (wrong error message)");
          console.log(`   Expected error containing: ${test.expectedErrorContains}`);
          console.log(`   Got: ${result.error.issues.map(i => i.message).join(", ")}`);
          failed++;
        } else {
          console.log("✅ PASS (expected validation error)");
          passed++;
        }
      } else {
        console.log("❌ FAIL (expected validation error but succeeded)");
        failed++;
      }
    } else if (result.success) {
