    const isMuted = execSync('osascript -e "output muted of (get volume settings)"', {
      encoding: "utf-8",
      stdio: ["pipe", "pipe", "pipe"]
    }).trim();

    return volume === 0 || isMuted === "true";
  } catch {
    debug("isMacMuted: failed to check mute status, assuming not muted");
    return false;
